// Security headers
app.use(helmet());

// CORS — restrict to known origin
app.use(cors({
  origin: process.env.ALLOWED_ORIGIN || 'https://yourdomain.com',
  methods: ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));

// Request logging
app.use(morgan('combined'));

// Rate limiting
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
}));

// Body parsing with size limit (future-proof)
app.use(express.json({ limit: '10kb' }));

// HTTPS redirect in production
app.set('trust proxy', 1);
app.use((req, res, next) => {
  if (req.secure || process.env.NODE_ENV !== 'production') return next();
  res.redirect(301, `https://${req.headers.host}${req.url}`);
});

// Auth middleware
const jwt = require('jsonwebtoken');
function requireAuth(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  try {
    req.user = jwt.verify(authHeader.slice(7), process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
}

// Routes
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

app.get('/users', requireAuth, (req, res) => {
  console.log({ event: 'users_listed', user: req.user?.sub, ip: req.ip, ts: new Date().toISOString() });
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// Global error handler (must be last)
app.use((err, req, res, next) => {
  console.error({ event: 'unhandled_error', message: err.message, stack: err.stack });
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal Server Error' : err.message,
  });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;
```

